#include <bits/stdc++.h>
using namespace std;
int n, p;
int c[100005];
struct Edge {
	int from, to;
	int w;
};
Edge make_up[100005];
int ans;
int minn = 1e9;
int father[100005];
void init() {
	for ( int i = 1 ; i <= n ; i++ ) {
		father[i] = i;
	}
}
int fid( int x ) {
	if ( x != father[x] ) {
		father[x] = fid( father[x] );
	}
	return father[x];
}
void Union( int x, int y ) {
	int a = fid( x ), b = fid( y );
	if ( a != b ) {
		father[b] = a;
	}
}
bool cmp( Edge x, Edge y ) {
	return x.w < y.w;
}
int main() {
	cin >> n >> p;
	init();
	for ( int i = 1 ; i <= n ; i++ ) {
		cin >> c[i];
		minn = min( minn, c[i] );
	}
	for ( int i = 1 ; i <= p ; i++ ) {
		int uu, vv, ww;
		cin >> uu >> vv >> ww;
		make_up[i] = { uu, vv, ww * 2 + c[uu] + c[vv] };
	}
	sort( make_up + 1, make_up + p + 1, cmp );
	for ( int i = 1 ; i <= p ; i++ ) {
		int u = make_up[i].from;
		int v = make_up[i].to;
		if ( fid( u ) == fid( v ) ) {
			continue;
		}
		Union( u, v );
		ans += make_up[i].w;
	}
	cout << ans + minn;
	return 0;
}
